I don't have an apple pencil to validate this scenario or explore a full solution, but I tried a few things. I added the following in `AppDelegate.swift` and was able to remove some buttons from the toolbar. It might not be a proper fix, just sharing it as a finding.

<details>
<summary>AppDelegate.swift (Click to Expand)</summary>

```swift
import Flutter
import UIKit
import ObjectiveC

@main
@objc class AppDelegate: FlutterAppDelegate {
  override func application(
    _ application: UIApplication,
    didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
  ) -> Bool {
    GeneratedPluginRegistrant.register(with: self)
    UITextInputAssistantItem.disableSystemInputAssistant()
    UIResponder.disableTextPlaceholderInsertion()
    return super.application(application, didFinishLaunchingWithOptions: launchOptions)
  }
}

extension UITextInputAssistantItem {
    static func disableSystemInputAssistant() {
        let originalLeading = class_getInstanceMethod(UITextInputAssistantItem.self, #selector(getter: leadingBarButtonGroups))
        let swizzledLeading = class_getInstanceMethod(UITextInputAssistantItem.self, #selector(emptyLeading))

        if let originalLeading = originalLeading, let swizzledLeading = swizzledLeading {
            method_exchangeImplementations(originalLeading, swizzledLeading)
        }

        let originalTrailing = class_getInstanceMethod(UITextInputAssistantItem.self, #selector(getter: trailingBarButtonGroups))
        let swizzledTrailing = class_getInstanceMethod(UITextInputAssistantItem.self, #selector(emptyTrailing))

        if let originalTrailing = originalTrailing, let swizzledTrailing = swizzledTrailing {
            method_exchangeImplementations(originalTrailing, swizzledTrailing)
        }
    }

    @objc func emptyLeading() -> [UIBarButtonItemGroup] {
        return []
    }

    @objc func emptyTrailing() -> [UIBarButtonItemGroup] {
        return []
    }
}

extension UIResponder {
    @objc func insertTextPlaceholder(withSize size: CGSize) -> UITextPlaceholder? {
        return nil
    }

    @objc func removeTextPlaceholder(_ placeholder: UITextPlaceholder) { }

    static func disableTextPlaceholderInsertion() {
        let originalInsert = class_getInstanceMethod(UIResponder.self, NSSelectorFromString("insertTextPlaceholderWithSize:"))
        let customInsert = class_getInstanceMethod(UIResponder.self, #selector(UIResponder.insertTextPlaceholder(withSize:)))

        if let originalInsert, let customInsert {
            method_exchangeImplementations(originalInsert, customInsert)
        }

        let originalRemove = class_getInstanceMethod(UIResponder.self, NSSelectorFromString("removeTextPlaceholder:"))
        let customRemove = class_getInstanceMethod(UIResponder.self, #selector(UIResponder.removeTextPlaceholder(_:)))

        if let originalRemove, let customRemove {
            method_exchangeImplementations(originalRemove, customRemove)
        }
    }
}
